import{_ as e,o as a,c as s,a2 as n}from"./chunks/framework.CZqXuAiL.js";const b=JSON.parse('{"title":"Ban System","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/mitigation/bans.md","filePath":"openshield-xdp/mitigation/bans.md","lastUpdated":1782412920000}'),d={name:"openshield-xdp/mitigation/bans.md"};function r(i,t,o,c,l,p){return a(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="ban-system" tabindex="-1">Ban System <a class="header-anchor" href="#ban-system" aria-label="Permalink to &quot;Ban System&quot;">​</a></h1><p>When an IP&#39;s suspicion score reaches the effective threshold, a ban entry is inserted. Ban entries are checked on every packet against every source IP.</p><h2 id="ban-lifecycle" tabindex="-1">Ban lifecycle <a class="header-anchor" href="#ban-lifecycle" aria-label="Permalink to &quot;Ban lifecycle&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Suspicion ≥ threshold → insert ban_entry{expiry, reason, score}</span></span>
<span class="line"><span>                      → increment ban_count (repeat offender tracking)</span></span>
<span class="line"><span>                      → emit event via ring buffer</span></span>
<span class="line"><span>                      → userspace webhook (if configured)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ban checks (every packet):</span></span>
<span class="line"><span>  Single IP → ban_map lookup → if matched and expiry &gt; now → DROP</span></span>
<span class="line"><span>  Subnet    → LPM trie lookup → longest prefix match → if matched → DROP</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ban expiry (userspace every 5s):</span></span>
<span class="line"><span>  ban_manager iterates ban maps → deletes entries where expiry ≤ now</span></span>
<span class="line"><span>                                  → decays star level if eligible</span></span></code></pre></div><h2 id="ban-types" tabindex="-1">Ban types <a class="header-anchor" href="#ban-types" aria-label="Permalink to &quot;Ban types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Map</th><th>Mechanism</th></tr></thead><tbody><tr><td>Single-IP (IPv4)</td><td><code>ban_map</code></td><td>HASH lookup by source IP</td></tr><tr><td>Single-IP (IPv6)</td><td><code>ban_map_v6</code></td><td>HASH lookup by ip6_key</td></tr><tr><td>Subnet (IPv4)</td><td><code>subnet_ban_map</code></td><td>LPM trie, longest prefix match</td></tr><tr><td>Subnet (IPv6)</td><td><code>subnet_ban_map_v6</code></td><td>LPM trie</td></tr></tbody></table><h2 id="auto-subnet-escalation" tabindex="-1">Auto subnet escalation <a class="header-anchor" href="#auto-subnet-escalation" aria-label="Permalink to &quot;Auto subnet escalation&quot;">​</a></h2><p>When <code>auto_escalation_enabled: true</code>, each single-IP ban in a /24 prefix increments a PERCPU counter. When the counter reaches <code>auto_escalation_threshold</code> (default 5), a /24 subnet ban is inserted with <code>duration = ban_duration * 2</code>.</p><h2 id="star-system" tabindex="-1">Star system <a class="header-anchor" href="#star-system" aria-label="Permalink to &quot;Star system&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Star</th><th>Duration multiplier</th><th>Clean period</th></tr></thead><tbody><tr><td>0 (first)</td><td>×1</td><td>—</td></tr><tr><td>1</td><td>×2</td><td><code>star_decay_seconds</code></td></tr><tr><td>2</td><td>×4</td><td>↓</td></tr><tr><td>3</td><td>×8</td><td>↓</td></tr><tr><td>4</td><td>×16</td><td>↓</td></tr><tr><td>5 (max)</td><td>×32</td><td>—</td></tr></tbody></table><p>Stars decay by 1 level after <code>star_decay_seconds</code> (default 3600s) of clean behaviour. Handled by the userspace ban manager.</p><h2 id="ban-reason-codes" tabindex="-1">Ban reason codes <a class="header-anchor" href="#ban-reason-codes" aria-label="Permalink to &quot;Ban reason codes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Code</th><th>Reason</th></tr></thead><tbody><tr><td>1</td><td>PPS exceeded</td></tr><tr><td>2</td><td>BPS exceeded</td></tr><tr><td>3</td><td>TCP PPS exceeded</td></tr><tr><td>4</td><td>UDP PPS exceeded</td></tr><tr><td>5</td><td>ICMP PPS exceeded</td></tr><tr><td>6</td><td>SYN PPS exceeded</td></tr><tr><td>7</td><td>New source flood</td></tr><tr><td>8</td><td>Bogus TCP flags</td></tr><tr><td>9</td><td>Connection rate</td></tr><tr><td>10</td><td>TTL anomaly</td></tr><tr><td>11</td><td>Packet size anomaly</td></tr><tr><td>12</td><td>Entropy spoofing</td></tr><tr><td>13</td><td>SYN/FIN ratio</td></tr></tbody></table><h2 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h2><p>Bans survive across loader restarts (maps are pinned). IP statistics are cleared on restart.</p><h2 id="related-pages" tabindex="-1">Related pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related pages&quot;">​</a></h2><p><a href="/pingless-studios-docs/openshield-xdp/mitigation/rate-limiting">Rate Limiting</a> · <a href="/pingless-studios-docs/openshield-xdp/mitigation/whitelist">Whitelist</a> · <a href="/pingless-studios-docs/openshield-xdp/detection-engine/rate-based">Rate-Based Detection</a></p>`,17)])])}const u=e(d,[["render",r]]);export{b as __pageData,u as default};
